import React from 'react';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';

const UnauthenticatedMenu = ({ categories }) => {
  // Filtrera kategorierna för att ta bort de som inte innehåller några spelare
  const filteredCategories = categories.filter(category => {
    return category.subMenu && category.subMenu.length > 0 && // MainMenus som har subMenus
      category.subMenu.some(subMenu => subMenu.players && subMenu.players.length > 0); // MainMenus som har subMenus med spelare
  });

  return (
    <div>
      {filteredCategories.map((category, index) => (
        <div key={index}>
          <ListItemText primary={category.mainMenu} />
          <List component="div" disablePadding>
            {category.subMenu.map((subItem, subIndex) => {
              if (subItem && subItem.players && subItem.players.length > 0) { // Kontrollera om subMenu och players existerar
                return (
                  <ListItem key={`${category.mainMenu}-${subIndex}`} button>
                    <ListItemText primary={subItem} />
                  </ListItem>
                );
              }
              return null;
            })}
          </List>
        </div>
      ))}
    </div>
  );
};

export default UnauthenticatedMenu;
